import React from 'react';
import {
    Box,
    Card,
    CardContent,
    Typography,
    LinearProgress,
    Button,
} from '@material-ui/core';
import { useHistory } from 'react-router-dom';
import StorageIcon from '@material-ui/icons/Storage';
import WarningIcon from '@material-ui/icons/Warning';
import SpeedIcon from '@material-ui/icons/Speed';

const Dashboard: React.FC = () => {
    const history = useHistory();

    const stats = [
        {
            icon: <StorageIcon sx={{ fontSize: 32 }} />,
            label: 'Datasets Processed',
            value: '12',
            color: '#667eea',
            trend: '+2 this month',
        },
        {
            icon: <WarningIcon sx={{ fontSize: 32 }} />,
            label: 'Attacks Detected',
            value: '847',
            color: '#f44336',
            trend: '+15% this week',
        },
        {
            icon: <SpeedIcon sx={{ fontSize: 32 }} />,
            label: 'Detection Rate',
            value: '94.2%',
            color: '#4caf50',
            trend: 'Excellent',
        },
    ];

    return (
        <Box>
            <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', sm: '1fr 1fr', md: '1fr 1fr 1fr' }, gap: 3, mb: 4 }}>
                {stats.map((stat, index) => (
                    <Card
                        key={index}
                        sx={{
                            height: '100%',
                            background: `linear-gradient(135deg, ${stat.color}15 0%, ${stat.color}05 100%)`,
                            border: `1px solid ${stat.color}30`,
                            transition: 'all 0.3s',
                            '&:hover': {
                                transform: 'translateY(-8px)',
                                boxShadow: `0 12px 32px ${stat.color}25`,
                            },
                        }}
                    >
                        <CardContent>
                            <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                                <Box sx={{ color: stat.color, mr: 1 }}>{stat.icon}</Box>
                                <Typography variant="body2" color="text.secondary">
                                    {stat.label}
                                </Typography>
                            </Box>
                            <Typography
                                variant="h4"
                                sx={{
                                    fontWeight: 'bold',
                                    color: stat.color,
                                    mb: 1,
                                }}
                            >
                                {stat.value}
                            </Typography>
                            <Typography variant="caption" color="text.secondary">
                                {stat.trend}
                            </Typography>
                        </CardContent>
                    </Card>
                ))}
            </Box>

            {/* Recent Activity */}
            <Card sx={{ mb: 4, background: 'rgba(102, 126, 234, 0.05)' }}>
                <CardContent>
                    <Typography variant="h6" sx={{ fontWeight: 'bold', mb: 3 }}>
                        System Status
                    </Typography>

                    <Box sx={{ mb: 3 }}>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                            <Typography variant="body2">Model Accuracy</Typography>
                            <Typography variant="body2" sx={{ fontWeight: 'bold', color: '#667eea' }}>
                                94.2%
                            </Typography>
                        </Box>
                        <LinearProgress
                            variant="determinate"
                            value={94.2}
                            sx={{
                                height: 8,
                                borderRadius: 4,
                                backgroundColor: '#e0e0e0',
                                '& .MuiLinearProgress-bar': {
                                    background: 'linear-gradient(90deg, #667eea 0%, #764ba2 100%)',
                                    borderRadius: 4,
                                },
                            }}
                        />
                    </Box>

                    <Box sx={{ mb: 3 }}>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                            <Typography variant="body2">Data Processing</Typography>
                            <Typography variant="body2" sx={{ fontWeight: 'bold', color: '#4caf50' }}>
                                100%
                            </Typography>
                        </Box>
                        <LinearProgress
                            variant="determinate"
                            value={100}
                            sx={{
                                height: 8,
                                borderRadius: 4,
                                backgroundColor: '#e0e0e0',
                                '& .MuiLinearProgress-bar': {
                                    background: 'linear-gradient(90deg, #4caf50 0%, #45a049 100%)',
                                    borderRadius: 4,
                                },
                            }}
                        />
                    </Box>

                    <Box>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                            <Typography variant="body2">System Health</Typography>
                            <Typography variant="body2" sx={{ fontWeight: 'bold', color: '#ff9800' }}>
                                98%
                            </Typography>
                        </Box>
                        <LinearProgress
                            variant="determinate"
                            value={98}
                            sx={{
                                height: 8,
                                borderRadius: 4,
                                backgroundColor: '#e0e0e0',
                                '& .MuiLinearProgress-bar': {
                                    background: 'linear-gradient(90deg, #ff9800 0%, #fb8c00 100%)',
                                    borderRadius: 4,
                                },
                            }}
                        />
                    </Box>
                </CardContent>
            </Card>

            {/* Quick Actions */}
            <Card>
                <CardContent>
                    <Typography variant="h6" style={{ fontWeight: 'bold', marginBottom: '24px' }}>
                        Quick Actions
                    </Typography>
                    <Box style={{ display: 'flex', gap: '16px', flexWrap: 'wrap' }}>
                        <Button
                            fullWidth
                            variant="contained"
                            onClick={() => history.push('/upload')}
                            style={{
                                background: 'linear-gradient(90deg, #667eea 0%, #764ba2 100%)',
                                textTransform: 'none',
                                fontSize: '1rem',
                                flex: 1,
                                minWidth: '200px',
                            }}
                        >
                            Upload New Dataset
                        </Button>
                        <Button
                            fullWidth
                            variant="outlined"
                            onClick={() => history.push('/results')}
                            style={{
                                borderColor: '#667eea',
                                color: '#667eea',
                                textTransform: 'none',
                                fontSize: '1rem',
                                flex: 1,
                                minWidth: '200px',
                            }}
                        >
                            View Results
                        </Button>
                    </Box>
                </CardContent>
            </Card>
        </Box>
    );
};

export default Dashboard;
